21.query:
fetch logs, scanLimitGBytes: 500
| search("n8n.workflow")
| parse content, "JSON:json_content"
/* We must use the timestamp in the content
*  NOT the `timestamp` field because remember, the Dynatrace collector gathers and sends logs in at an interval
*  thus, according to DT a started + finished `timestamp` could be the same (its the time both log lines hit Dynatrace)
* and NOT the time they actually occurred.
* This time they actually occurred is content[ts]
*/
| fieldsAdd payload = json_content[payload]
| fieldsAdd realTS = json_content[ts]
| fieldsAdd errorMessage = payload[errorMessage]
| fields realTS, executionID = payload[`executionId`], eventName = json_content[`eventName`], workflowID = payload[`workflowId`], isManual = payload[`isManual`], workflowName = payload[`workflowName`], errorMessage
// Combining the data by the executionID
// First sort by execution ID and timestamp to ensure all .started are first
| sort executionID, realTS
| summarize t = collectArray(record(realTS = toTimestamp(realTS), eventName, workflowID, workflowName, errorMessage)), by:{executionID}
// Re-add the fields as standalone fields
// Note the isNull check for error message:
// Most workflows (hopefully are successful and thus won't have an error message
// ie. errorMessage will be null - in which case, just to an empty string
// If there is an errorMessage, use it
| fieldsAdd workflowID = t[0][workflowID]
| fieldsAdd workflowName = t[0][workflowName]
// Generate human readable status
// Split the status and if it isn't null (will occur when the workflow is running)
// take the last part
| fieldsAdd workflowStatus = if(isNotNull(splitString(t[1][eventName], ".")[2]), if(splitString(t[1][eventName], ".")[2] == "success", "✅ Success", else: "❌ Error"), else: "🔜 Running...")
| sort t[][eventName]
// Convoluted logic that checks both fields for an error message
// When there is no error (ie. a successful run) the field is null, hence the nested if/else
| fieldsAdd errorMessage = if (t[1][eventName] == "n8n.workflow.failed", t[1][errorMessage], else: (if(isNull(t[0][errorMessage]), "", else: t[0][errorMessage])))
// if(isNull(t[0][errorMessage]), "", else: t[1][errorMessage])
// Calculate execution time
// If the workflow is currently running it may not have a value
// In which case, set the value to "-"
// Note: The eventNames are sorted alphabetically so during a success:
// n8n.workflow.started (ie. the start time) comes before n8n.workflow.success (ie. the finish time)
// BUT during a failure:
// n8n.workflow.failed (ie. the finish time) comes before n8n.workflow.started (ie. the start time)
// which could lead to correct (but negative) timings for failed workflows (eg. -185ms where it should be 185ms)
// Hence the nested ifs in the line below account for this possibility
| fieldsAdd `execution time` = if(t[0][eventName] == "n8n.workflow.started", (if(isNull(t[1][realTS] - t[0][realTS]), "-", else: t[1][realTS] - t[0][realTS])), else: (if(isNull(t[0][realTS] - t[1][realTS]), "-", else: t[0][realTS] - t[1][realTS])))
| fieldsAdd `workflow run` = concat("[", workflowName, "](", concat($WorkflowID, "/workflow/", workflowID, "/executions/", executionID), ")")
// Clean up fields
| filter in($WorkflowID , "ALL") OR in(workflowID, $WorkflowID)

| fieldsRemove t, workflowID, workflowName
| sort toLong(executionID) desc

24.query:
fetch logs
| search("EventMessageAiNode")
| parse content, """JSON {
 JSON {
  STRING:workflowName,
  STRING:nodeType,
  STRING:workflowId,
  JSON {
    JSON {
      STRING:model
    }:options,
    JSON {
      JSON {
        INT:completionTokens,
        INT:promptTokens,
        INT:totalTokens
      }:tokenUsage
    }:response
  }:msg
 }:payload
}:all"""
| filter in($WorkflowID , "ALL") OR in(all[payload][workflowId], $WorkflowID)
| summarize sum(all[payload][msg][response][tokenUsage][totalTokens]), alias:totalTokens

